noncompliant:
char* p = (char*)malloc(100);
free(p);
*p = 'a'; // Noncompliant: accessing freed memory

int* ptr = new int(42);
delete ptr;
int value = *ptr; // Noncompliant: dereferencing freed memory

compliant:
char* p = (char*)malloc(100);
*p = 'a'; // Use before freeing
free(p);
p = nullptr; // Set to null after freeing

int* ptr = new int(42);
int value = *ptr; // Use before deleting
delete ptr;
ptr = nullptr; // Set to null after deleting
